 27→//// Activation Functions
 28→
 29→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 30→static inline vint16m4_t tanh_s16_v(vint16m4_t vOut_s16, long vl)
 31→{
 32→    vint16m4_t vOut2_s16 = __riscv_vrsub(vOut_s16, 0, vl);              //neg_in
 33→    vbool4_t vMask = nn_mask_if_less_than_vi_i16m4(vOut_s16, 0, vl);    //mask_if_negative
 34→    vbool4_t vZero = nn_mask_if_zero(vOut_s16, vl);                     //mask_if_zero
 35→    vOut_s16 = nn_select_using_mask_vv(vOut2_s16, vOut_s16, vMask, vl); //n
 36→
 37→    vOut_s16 = nn_neg_tanh_on_negative_values_v(vOut_s16, vl);
 38→
 39→    vint16m4_t vTemp_s16 = __riscv_vrsub(vOut_s16, 0, vl);              //neg_t
 40→    vOut_s16 = nn_select_using_mask_vv(vOut_s16, vTemp_s16, vMask, vl); //out
 41→    vOut_s16 = nn_select_using_mask_vi(vOut_s16, 0, vZero, vl);         //out
 42→    return vOut_s16;
 43→}
 44→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
 45→/**
 46→ * @brief           it's used to simulate tanh_s16 with v-ext
 47→ * @param[in]       the avl
 48→ *
 49→ * @note
 50→ *  - the LMUL is assumed has been set to 4
 51→ *  - the SEW is expected to be set to 16 already
 52→ *  - the inputs are assumed to be stored in v4~v7 already
 53→ */
 54→static inline void tanh_s16_v(long vl)
 55→{
 56→    NDS_VEC_VRSUB_VI(NDS_VEC_V8, NDS_VEC_V4, 0);                //neg_in
 57→    NN_MASK_IF_LESS_THAN_VI(NDS_VEC_V0, NDS_VEC_V4, 0);           //mask_if_negative
 58→    NN_MASK_IF_ZERO(NDS_VEC_V1, NDS_VEC_V4);                      //mask_if_zero
 59→    NN_SELECT_USING_MASK_VV(NDS_VEC_V4, NDS_VEC_V8, NDS_VEC_V4);  //n
 60→    NDS_VEC_VMMV_M(NDS_VEC_V2, NDS_VEC_V0);                     //backup mask_if_negative
 61→
 62→    neg_tanh_on_negative_values_v(vl);
 63→
 64→    NDS_VEC_VMMV_M(NDS_VEC_V0, NDS_VEC_V2);                     //restore mask_if_negative
 65→    NDS_VEC_VRSUB_VI(NDS_VEC_V8, NDS_VEC_V4, 0);                //neg_t
 66→    NN_SELECT_USING_MASK_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V8);  //out
 67→    NDS_VEC_VMMV_M(NDS_VEC_V0, NDS_VEC_V1);                     //mask_if_zero
 68→    NN_SELECT_USING_MASK_VI(NDS_VEC_V4, NDS_VEC_V4, 0);           //out
 69→}
 70→#endif
 71→
 72→#ifdef ENA_DSP_ISA
 73→static inline void tanh_s16(int32_t in, int32_t* pOut)
 74→{
 75→    int32_t mask_if_negative = MASK_IF_LESS_THAN(in, 0);
 76→    int32_t mask_if_zero = MASK_IF_ZERO(in);
 77→    int32_t neg_in = -in;
 78→    int32_t n = SELECT_USING_MASK(mask_if_negative, in, neg_in);
 79→    int32_t t = neg_tanh_on_negative_values(n);
 80→    int32_t neg_t = -t;
 81→    *pOut = SELECT_USING_MASK(mask_if_zero, 0, SELECT_USING_MASK(mask_if_negative, neg_t, t));
 82→}
 83→#endif
 84→
 85→void riscv_nn_tanh_s8(const int32_t in_offset,
 86→                      const int16_t in_range_radius,
 87→                      const int16_t in_mult,
 88→                      const int16_t in_shift,
 89→                      const uint32_t size,
 90→                      const int8_t* in_vec,
 91→                      int8_t* out_vec)
 92→{
 93→#ifdef ENA_EMPTY_FUN
 94→    //empty body
 95→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 96→    long vl;
 97→    long size2 = size;
 98→
 99→    const int32_t const_05 = 1 << 14;
100→    const int32_t const_05n = (1 - (1 << 14)) + (1 << 15) - 1; // div rounding need to add (1 << 15)
101→    const int16_t const_127 = 127;
102→    const int16_t const_128n = -128;
103→
104→    if(in_shift >= 0)
105→    {
106→        const int32_t mul_pow2 = 1L << in_shift;
107→        while(size2 > 0)
108→        {
109→            vl = __riscv_vsetvl_e8m2(size2);
110→            vint8m2_t vIn_s8 = __riscv_vle8_v_i8m2(in_vec, vl);
111→            vint16m4_t vIn_s16 = __riscv_vwadd_vx(vIn_s8, in_offset, vl);
112→
113→            vl = __riscv_vsetvl_e16m4(size2);
114→            vint32m8_t vIn_s32 = __riscv_vwmul(vIn_s16, (long) in_mult, vl);
115→
116→            // SaturatingRoundingDoublingHighMul_with_Lsh
117→            vl = __riscv_vsetvl_e32m8(size2);
118→            vint32m8_t vOut_s32 = __riscv_vmul(vIn_s32, mul_pow2, vl);      // (ab_32*(1L << left_shift))
119→            vbool4_t vMask = __riscv_vmslt(vIn_s32, 0, vl);                 // ab_32 < 0
120→            vint32m8_t vVal1 = __riscv_vadd(vOut_s32, const_05, vl);
121→            vint32m8_t vVal2 = __riscv_vadd(vOut_s32, const_05n, vl);
122→            vOut_s32 = __riscv_vmerge_vvm_i32m8(vVal1, vVal2, vMask, vl);
123→            vl = __riscv_vsetvl_e16m4(size2);
124→            vint16m4_t vOut_s16 = __riscv_vnsra(vOut_s32, 15, vl);
125→
126→            vOut_s16 = tanh_s16_v(vOut_s16, vl);
127→
128→            long mask = (1<<8)-1;
129→            vOut_s16 = nn_rounding_divide_by_pot16b_i16m4(vOut_s16, 8, mask, vl);
130→
131→            vl = __riscv_vsetvl_e8m2(size2);
132→            vIn_s8 = __riscv_vle8_v_i8m2(in_vec, vl);
133→            vIn_s16 = __riscv_vwadd_vx(vIn_s8, in_offset, vl);
134→
135→            vl = __riscv_vsetvl_e16m4(size2);
136→            vMask = __riscv_vmslt(vIn_s16, (long)-in_range_radius, vl);     // if input_val_centered < -in_range_radius
137→            vOut_s16 = __riscv_vmerge_vxm_i16m4(vOut_s16, const_128n, vMask, vl);
138→            vMask = __riscv_vmsgt(vIn_s16, (long)in_range_radius, vl);      // if input_val_centered > in_range_radius
139→            vOut_s16 = __riscv_vmerge_vxm_i16m4(vOut_s16, const_127, vMask, vl);
140→            vl = __riscv_vsetvl_e8m2(vl);
141→            vint8m2_t vOut_s8 = __riscv_vnclip(vOut_s16, 0, __RISCV_VXRM_RNU, vl);
142→            __riscv_vse8(out_vec, vOut_s8, vl);
143→
144→            out_vec += vl;
145→            in_vec += vl;
146→            size2 -= vl;
147→        }
148→    }
149→    else // in_shift < 0
150→    {
151→        const int32_t shift_right = -in_shift;
152→        while(size2 > 0)
153→        {
154→            vl = __riscv_vsetvl_e8m2(size2);
155→            vint8m2_t vIn_s8 = __riscv_vle8_v_i8m2(in_vec, vl);
156→            vint16m4_t vIn_s16 = __riscv_vwadd_vx(vIn_s8, in_offset, vl);
157→
158→            vl = __riscv_vsetvl_e16m4(size2);
159→            vint32m8_t vIn_s32 = __riscv_vwmul(vIn_s16, (long) in_mult, vl);
160→
161→            // SaturatingRoundingDoublingHighMul_with_Lsh
162→            vl = __riscv_vsetvl_e32m8(size2);
163→            vint32m8_t vOut_s32 = __riscv_vsra(vIn_s32, shift_right, vl);   // (ab_32 >> (-left_shift))
164→            vbool4_t vMask = __riscv_vmslt(vIn_s32, 0, vl);                 // ab_32 < 0
165→            vint32m8_t vVal1 = __riscv_vadd(vOut_s32, const_05, vl);
166→            vint32m8_t vVal2 = __riscv_vadd(vOut_s32, const_05n, vl);
167→            vOut_s32 = __riscv_vmerge_vvm_i32m8(vVal1, vVal2, vMask, vl);
168→            vl = __riscv_vsetvl_e16m4(size2);
169→            vint16m4_t vOut_s16 = __riscv_vnsra(vOut_s32, 15, vl);
170→
171→            vOut_s16 = tanh_s16_v(vOut_s16, vl);
172→
173→            long mask = (1<<8)-1;
174→            vOut_s16 = nn_rounding_divide_by_pot16b_i16m4(vOut_s16, 8, mask, vl);
175→
176→            vl = __riscv_vsetvl_e8m2(size2);
177→            vIn_s8 = __riscv_vle8_v_i8m2(in_vec, vl);
178→            vIn_s16 = __riscv_vwadd_vx(vIn_s8, in_offset, vl);
179→
180→            vl = __riscv_vsetvl_e16m4(size2);
181→            vMask = __riscv_vmslt(vIn_s16, (long)-in_range_radius, vl);     // if input_val_centered < -in_range_radius
182→            vOut_s16 = __riscv_vmerge_vxm_i16m4(vOut_s16, const_128n, vMask, vl);
183→            vMask = __riscv_vmsgt(vIn_s16, (long)in_range_radius, vl);      // if input_val_centered > in_range_radius
184→            vOut_s16 = __riscv_vmerge_vxm_i16m4(vOut_s16, const_127, vMask, vl);
185→            vl = __riscv_vsetvl_e8m2(vl);
186→            vint8m2_t vOut_s8 = __riscv_vnclip(vOut_s16, 0, __RISCV_VXRM_RNU, vl);
187→            __riscv_vse8(out_vec, vOut_s8, vl);
188→
189→            out_vec += vl;
190→            in_vec += vl;
191→            size2 -= vl;
192→        }
193→    }
194→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
195→    long vl;
196→    long size2 = size;
197→
198→    const int32_t const_05 = 1 << 14;
199→    const int32_t const_05n = (1 - (1 << 14)) + (1 << 15) - 1; // div rounding need to add (1 << 15)
200→    const int16_t const_127 = 127;
201→    const int16_t const_128n = -128;
202→
203→    if(in_shift >= 0)
204→    {
205→        const int32_t mul_pow2 = 1L << in_shift;
206→        while(size2 > 0)
207→        {
208→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
209→            NDS_VEC_VLE8_V(NDS_VEC_V0, in_vec);
210→            NDS_VEC_VWADD_VX(NDS_VEC_V24, NDS_VEC_V0, in_offset);
211→
212→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
213→            NDS_VEC_VWMUL_VX(NDS_VEC_V16, NDS_VEC_V24, (long) in_mult);
214→
215→            // SaturatingRoundingDoublingHighMul_with_Lsh
216→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
217→            NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V16, mul_pow2);     // (ab_32*(1L << left_shift))
218→            NDS_VEC_VMSLT_VI(NDS_VEC_V0, NDS_VEC_V16, 0);           // ab_32 < 0
219→            NDS_VEC_VADD_VX(NDS_VEC_V16, NDS_VEC_V8, const_05);
220→            NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V8, const_05n);
221→            NDS_VEC_VMERGE_VVM(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
222→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
223→            NDS_VEC_VNSRA_WI(NDS_VEC_V4, NDS_VEC_V16, 15);
224→
225→            tanh_s16_v(vl);
226→
227→            long mask = (1<<8)-1;
228→            NN_RoundingDivideByPOT16b(NDS_VEC_V4, NDS_VEC_V4, 8, mask, NDS_VEC_V8, NDS_VEC_V12);
229→
230→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
231→            NDS_VEC_VLE8_V(NDS_VEC_V24, in_vec);
232→            NDS_VEC_VWADD_VX(NDS_VEC_V28, NDS_VEC_V24, in_offset);
233→
234→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
235→            NDS_VEC_VMSLT_VX(NDS_VEC_V0, NDS_VEC_V28, (long)-in_range_radius); // if input_val_centered < -in_range_radius
236→            NDS_VEC_VMERGE_VXM(NDS_VEC_V4, NDS_VEC_V4, const_128n);
237→            NDS_VEC_VMSGT_VX(NDS_VEC_V0, NDS_VEC_V28, (long)in_range_radius); // if input_val_centered > in_range_radius
238→            NDS_VEC_VMERGE_VXM(NDS_VEC_V4, NDS_VEC_V4, const_127);
239→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
240→            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V4, 0);
241→            NDS_VEC_VSE8_V(NDS_VEC_V8, out_vec);
242→
243→            out_vec += vl;
244→            in_vec += vl;
245→            size2 -= vl;
246→        }
247→    }
248→    else // in_shift < 0
249→    {
250→        const int32_t shift_right = -in_shift;
251→        while(size2 > 0)
252→        {
253→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
254→            NDS_VEC_VLE8_V(NDS_VEC_V0, in_vec);
255→            NDS_VEC_VWADD_VX(NDS_VEC_V24, NDS_VEC_V0, in_offset);
256→
257→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
258→            NDS_VEC_VWMUL_VX(NDS_VEC_V16, NDS_VEC_V24, (long) in_mult);
259→
260→            // SaturatingRoundingDoublingHighMul_with_Lsh
261→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
262→            NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V16, shift_right);      // (ab_32 >> (-left_shift))
263→            NDS_VEC_VMSLT_VI(NDS_VEC_V0, NDS_VEC_V16, 0);               // ab_32 < 0
264→            NDS_VEC_VADD_VX(NDS_VEC_V16, NDS_VEC_V8, const_05);
265→            NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V8, const_05n);
266→            NDS_VEC_VMERGE_VVM(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
267→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
268→            NDS_VEC_VNSRA_WI(NDS_VEC_V4, NDS_VEC_V16, 15);
269→
270→            tanh_s16_v(vl);
271→
272→            long mask = (1<<8)-1;
273→            NN_RoundingDivideByPOT16b(NDS_VEC_V4, NDS_VEC_V4, 8, mask, NDS_VEC_V8, NDS_VEC_V12);
274→
275→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
276→            NDS_VEC_VLE8_V(NDS_VEC_V24, in_vec);
277→            NDS_VEC_VWADD_VX(NDS_VEC_V28, NDS_VEC_V24, in_offset);
278→
279→            NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
280→            NDS_VEC_VMSLT_VX(NDS_VEC_V0, NDS_VEC_V28, (long)-in_range_radius); // if input_val_centered < -in_range_radius
281→            NDS_VEC_VMERGE_VXM(NDS_VEC_V4, NDS_VEC_V4, const_128n);
282→            NDS_VEC_VMSGT_VX(NDS_VEC_V0, NDS_VEC_V28, (long)in_range_radius); // if input_val_centered > in_range_radius
283→            NDS_VEC_VMERGE_VXM(NDS_VEC_V4, NDS_VEC_V4, const_127);
284→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
285→            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V4, 0);
286→            NDS_VEC_VSE8_V(NDS_VEC_V8, out_vec);
287→
288→            out_vec += vl;
289→            in_vec += vl;
290→            size2 -= vl;
291→        }
292→    }
293→#elif defined(ENA_DSP_ISA)
294→    int32_t c = 0;
295→    for (c = 0; c < size; ++c)
296→    {
297→        const int8_t input_val_s8 = in_vec[c];
298→        const int16_t input_val_centered = (int16_t)(input_val_s8) + in_offset; // -input_zero_point;
299→
300→        int8_t output_val;
301→        if (input_val_centered < -in_range_radius)
302→        {
303→            output_val = -128;
304→        }
305→        else if (input_val_centered > in_range_radius)
306→        {
307→            output_val = 127;
308→        }
309→        else
310→        {
311→            //Rescale input (in_scale & fixedpointlization) to fixed point representation.
312→            const int16_t input_val_rescaled = SaturatingRoundingDoublingHighMul_with_Lsh(
313→                (int16_t)(input_val_centered),
314→                (int16_t)(in_mult), in_shift);
315→
316→            int32_t output_val_s16;
317→            tanh_s16(input_val_rescaled, &output_val_s16);
318→
319→            //Rescale (inverse fixedpointization & requanitzation) to q7_t representation.
320→            output_val_s16 = RoundingDivideByPOT16b(output_val_s16, 8);
321→
322→            if (output_val_s16 == 128)
323→            {
324→                output_val_s16 = 127;
325→            }
326→            output_val = (int8_t)(output_val_s16);
327→        }
328→        out_vec[c] = output_val;
329→    }
330→#else
331→    const int16_t output_offset = 0;
332→
333→    int32_t c = 0;
334→    for (c = 0; c < size; ++c)
335→    {
336→        const int8_t input_val_s8 = in_vec[c];
337→        const int16_t input_val_centered = (int16_t)(input_val_s8) + in_offset; // -input_zero_point;
338→
339→        int8_t output_val;
340→        if (input_val_centered < -in_range_radius)
341→        {
342→            output_val = -128;
343→        }
344→        else if (input_val_centered > in_range_radius)
345→        {
346→            output_val = 127;
347→        }
348→        else
349→        {
350→            //Rescale input (in_scale & fixedpointlization) to fixed point representation.
351→            const int16_t input_val_rescaled = SaturatingRoundingDoublingHighMul_with_Lsh(
352→                (int16_t)(input_val_centered),
353→                (int16_t)(in_mult), in_shift);
354→
355→            //
356→            const struct FixedPoint input_val_f4 = FromRaw(input_val_rescaled, 4);//F4
357→            struct FixedPoint output_val_f0 = FromRaw(0, 0);
358→
359→            //kernel of tanh.
360→            tanh_s16(input_val_f4, &output_val_f0);
361→
362→            //Rescale (inverse fixedpointization & requanitzation) to q7_t representation.
363→            int16_t output_val_s16 = RoundingDivideByPOT16b(output_val_f0.i_, 8);
364→
365→            output_val_s16 += output_offset;
366→
367→            if (output_val_s16 == 128)
368→            {
369→                output_val_s16 = 127;
370→            }
371→            output_val = (int8_t)(output_val_s16);
372→        }
373→        out_vec[c] = output_val;
374→    }
375→#endif
376→}
