 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→
 24→//// Pooling Functions
 25→
 26→void riscv_nn_maxpool_HWC_s8(const q7_t * in_tensor,
 27→                             const uint16_t in_tensor_batch,
 28→                             const uint16_t in_tensor_dim,
 29→                             const uint16_t in_tensor_ch,
 30→                             const uint16_t ker_dim,
 31→                             const uint16_t pad,
 32→                             const uint16_t stride,
 33→                             const uint16_t out_tensor_dim,
 34→                             q7_t * in_tmp_buf,
 35→                             q7_t * out_tensor)
 36→{
 37→#ifdef ENA_EMPTY_FUN
 38→    //empty body
 39→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 40→    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
 41→    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
 42→
 43→    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
 44→    {
 45→        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
 46→        {
 47→            long ker_y_start = MAX(0, in_y);
 48→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
 49→            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
 50→            {
 51→                long ker_x_start = MAX(0, in_x);
 52→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
 53→                long cur_ch = 0, vl = 0;
 54→
 55→                long in_tensor_ch2 = in_tensor_ch;
 56→                while(in_tensor_ch2 > 0)
 57→                {
 58→                    // reset the max values
 59→                    vl = __riscv_vsetvl_e8m8(in_tensor_ch2);
 60→                    vint8m8_t vMax = __riscv_vmv_v_x_i8m8(0x80, vl);
 61→
 62→                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
 63→                    {
 64→                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
 65→                        {
 66→                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
 67→                            vint8m8_t vIn = __riscv_vle8_v_i8m8(in_ptr, vl);
 68→                            vMax = __riscv_vmax(vIn, vMax, vl);
 69→                        }
 70→                    }
 71→
 72→                    __riscv_vse8(out_tensor, vMax, vl);
 73→                    out_tensor += vl;
 74→                    cur_ch += vl;
 75→                    in_tensor_ch2 -= vl;
 76→                }
 77→            }
 78→        }
 79→        in_tensor += input_len;
 80→    }
 81→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
 82→    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
 83→    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
 84→
 85→    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
 86→    {
 87→        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
 88→        {
 89→            long ker_y_start = MAX(0, in_y);
 90→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
 91→            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
 92→            {
 93→                long ker_x_start = MAX(0, in_x);
 94→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
 95→                long cur_ch = 0, vl = 0;
 96→
 97→                long in_tensor_ch2 = in_tensor_ch;
 98→                while(in_tensor_ch2 > 0)
 99→                {
100→                    // reset the max values
101→                    NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
102→                    NDS_VEC_VMV_V_X(NDS_VEC_V0, 0x80);
103→
104→                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
105→                    {
106→                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
107→                        {
108→                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
109→                            NDS_VEC_VLE8_V(NDS_VEC_V8, in_ptr);
110→                            NDS_VEC_VMAX_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);
111→                        }
112→                    }
113→
114→                    NDS_VEC_VSE8_V(NDS_VEC_V0, out_tensor);
115→                    out_tensor += vl;
116→                    cur_ch += vl;
117→                    in_tensor_ch2 -= vl;
118→                }
119→            }
120→        }
121→        in_tensor += input_len;
122→    }
123→#elif defined(ENA_DSP_ISA_64)
124→    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
125→    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
126→
127→    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
128→    {
129→        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
130→        {
131→            long ker_y_start = MAX(0, in_y);
132→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
133→            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
134→            {
135→                long ker_x_start = MAX(0, in_x);
136→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
137→                long cur_ch;
138→                long out_q7x8;
139→
140→                for(cur_ch = 0; (cur_ch + 8) <= in_tensor_ch; cur_ch += 8)
141→                {
142→                    out_q7x8 = 0x8080808080808080;
143→                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
144→                    {
145→                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
146→                        {
147→                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
148→                            long in_q7x8 = *__SIMD64(in_ptr);
149→                            out_q7x8 = NDS_DSP_SMAX8(in_q7x8, out_q7x8);
150→                        }
151→                    }
152→
153→                    *__SIMD64(out_tensor) = out_q7x8;
154→                    out_tensor += 8;
155→                }
156→
157→                // rest channels
158→                for (; cur_ch < in_tensor_ch; cur_ch++)
159→                {
160→                    int max_val = (int8_t)Q7_MIN;
161→                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
162→                    {
163→                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
164→                        {
165→                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
166→                            max_val = MAX(*in_ptr, max_val);
167→                        }
168→                    }
169→                    *out_tensor++ = max_val;
170→                }
171→            }
172→        }
173→        in_tensor += input_len;
174→    }
175→#elif defined(ENA_DSP_ISA)
176→    long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
177→    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
178→
179→    for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
180→    {
181→        for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
182→        {
183→            long ker_y_start = MAX(0, in_y);
184→            long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
185→            for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
186→            {
187→                long ker_x_start = MAX(0, in_x);
188→                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
189→                uint32_t cur_ch;
190→                long out_q7x4;
191→
192→                for(cur_ch = 0; (cur_ch + 4) <= in_tensor_ch; cur_ch += 4)
193→                {
194→                    out_q7x4 = 0x80808080;
195→                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
196→                    {
197→                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
198→                        {
199→                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
200→                            long in_q7x4 = *__SIMD32(in_ptr);
201→                            out_q7x4 = NDS_DSP_SMAX8(in_q7x4, out_q7x4);
202→                        }
203→                    }
204→                    *__SIMD32(out_tensor) = out_q7x4;
205→                    out_tensor += 4;
206→                }
207→
208→                // rest channels
209→                for (; cur_ch < in_tensor_ch; cur_ch++)
210→                {
211→                    int max_val = (int8_t)Q7_MIN;
212→                    for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
213→                    {
214→                        for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
215→                        {
216→                            const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
217→                            max_val = MAX(*in_ptr, max_val);
218→                        }
219→                    }
220→                    *out_tensor++ = max_val;
221→                }
222→            }
223→        }
224→        in_tensor += input_len;
225→    }
226→#else
227→    int16_t i_batch, i_ch_in, i_x, i_y;
228→    int16_t k_x, k_y;
229→    const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;
230→    const int32_t output_len = out_tensor_dim * out_tensor_dim * in_tensor_ch;
231→
232→    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
233→    {
234→        for (i_ch_in = 0; i_ch_in < in_tensor_ch; i_ch_in++)
235→        {
236→            for (i_y = 0; i_y < out_tensor_dim; i_y++)
237→            {
238→                for (i_x = 0; i_x < out_tensor_dim; i_x++)
239→                {
240→                    int max = (int8_t)Q7_MIN;
241→                    for (k_y = i_y * stride - pad; k_y < i_y * stride - pad + ker_dim; k_y++)
242→                    {
243→                        for (k_x = i_x * stride - pad; k_x < i_x * stride - pad + ker_dim; k_x++)
244→                        {
245→                            if (k_y >= 0 && k_x >= 0 && k_y < in_tensor_dim && k_x < in_tensor_dim)
246→                            {
247→                                if (in_tensor[i_ch_in + in_tensor_ch * (k_x + k_y * in_tensor_dim)] > max)
248→                                {
249→                                    max = in_tensor[i_ch_in + in_tensor_ch * (k_x + k_y * in_tensor_dim)];
250→                                }
251→                            }
252→                        }
253→                    }
254→                    out_tensor[i_ch_in + in_tensor_ch * (i_x + i_y * out_tensor_dim)] = max;
255→                }
256→            }
257→        }
258→        in_tensor += input_len;
259→        out_tensor += output_len;
260→    }
261→#endif
262→
263→}
