 22→#include "internal_nn_math.h"
 23→
 24→//// Relu Functions
 25→
 26→void riscv_nn_leaky_relu_s8(q7_t * in_out,
 27→                          uint32_t size,
 28→                          q15_t slope)
 29→{
 30→#ifdef ENA_EMPTY_FUN
 31→    //empty body
 32→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 33→    long size2 = size;
 34→    while (size2 > 0)
 35→    {
 36→        long vl = __riscv_vsetvl_e16m8(size2);
 37→        vint8m4_t vin_out = __riscv_vle8_v_i8m4(in_out, vl);
 38→        vint16m8_t vin_out_ext = __riscv_vsext_vf2(vin_out, vl);
 39→        vbool2_t vin_out_masked = __riscv_vmslt(vin_out_ext, 0, vl);    //mask those elements < 0
 40→
 41→        //in * slope
 42→        vin_out_ext = __riscv_vsmul(vin_out_ext, slope, __RISCV_VXRM_RNU, vl);
 43→        //saturation
 44→        vl = __riscv_vsetvl_e8m4(vl);
 45→        vint8m4_t vin_out_saturated = __riscv_vnclip(vin_out_ext, 0, __RISCV_VXRM_RNU, vl);
 46→        //update results into input buffer
 47→        __riscv_vse8(vin_out_masked, in_out, vin_out_saturated, vl);
 48→
 49→        size2 -= vl;
 50→        in_out += vl;
 51→    }
 52→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
 53→    long size2 = size;
 54→    while (size2 > 0)
 55→    {
 56→        long vl;
 57→        NDS_VEC_VSETVLI(vl, size2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
 58→        NDS_VEC_VLE8_V(NDS_VEC_V4, in_out);
 59→        NDS_VEC_VSEXT_VF2(NDS_VEC_V8, NDS_VEC_V4);
 60→        NDS_VEC_VMSLT_VI(NDS_VEC_V0, NDS_VEC_V8, 0);    //mask those elements < 0
 61→
 62→        //in * slope
 63→        NDS_VEC_VSMUL_VX(NDS_VEC_V8, NDS_VEC_V8, slope);
 64→        //saturation
 65→        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
 66→        NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
 67→        //update results into input buffer
 68→        NDS_VEC_VMERGE_VVM(NDS_VEC_V16, NDS_VEC_V4, NDS_VEC_V8);
 69→        NDS_VEC_VSE8_V(NDS_VEC_V16, in_out);
 70→
 71→        size2 -= vl;
 72→        in_out += vl;
 73→    }
 74→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION == 80)
 75→    while (size > 0)
 76→    {
 77→        uint32_t vl;
 78→        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M8);
 79→        NDS_VEC_VLB_V(NDS_VEC_V8, in_out);
 80→        NDS_VEC_VMSLT_VI(NDS_VEC_V0, NDS_VEC_V8, 0);    //mask those elements < 0
 81→
 82→        //in * slope
 83→        NDS_VEC_VSMUL_VX(NDS_VEC_V16, NDS_VEC_V8, slope);
 84→        //saturation
 85→        NDS_VEC_VMAX_VX(NDS_VEC_V16, NDS_VEC_V16, 0xffffff80);
 86→        NDS_VEC_VMIN_VX(NDS_VEC_V16, NDS_VEC_V16, 0x0000007f);
 87→        //update results into input buffer
 88→        NDS_VEC_MSK_VSB_V(NDS_VEC_V16, in_out);
 89→
 90→        size -= vl;
 91→        in_out += vl;
 92→    }
