//// Pooling Functions

void riscv_nn_maxpool_HWC_s8(const q7_t * in_tensor,
                             const uint16_t in_tensor_batch,
                             const uint16_t in_tensor_dim,
                             const uint16_t in_tensor_ch,
                             const uint16_t ker_dim,
