                long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
                long cur_ch = 0, vl = 0;

                long in_tensor_ch2 = in_tensor_ch;
                while(in_tensor_ch2 > 0)
                {
                    // reset the max values
                    NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
